# STORY-028 Deliverable — Kanban v2: Pull-to-refresh, Theme Toggle, Empty States, Offline Detection

**Author:** Claude (Meta-Agent / Board Manager)
**Date:** 2026-06-27
**Status:** Complete

---

## 1. Overview

This deliverable covers four UX improvements for the Kanban board:

1. **Pull-to-refresh** — mobile-friendly gesture to reload board data.
2. **Theme toggle** — light/dark mode switch persisted to localStorage.
3. **Empty states** — friendly messaging when columns or boards have no content.
4. **Offline detection** — banner + queue when the network drops.

Each feature is self-contained, testable, and degrades gracefully.

---

## 2. Pull-to-Refresh

### Approach
Use a custom hook `usePullToRefresh` that listens to `touchstart`/`touchmove`/`touchend` and triggers a refresh when the user pulls down ≥60px from the top while already scrolled to the top.

### Implementation

```tsx
// src/hooks/usePullToRefresh.ts
import { useEffect, useRef } from 'react'

export function usePullToRefresh(onRefresh: () => Promise<void>, disabled = false) {
  const startY = useRef(0)
  const distance = useRef(0)

  useEffect(() => {
    if (disabled) return

    const onTouchStart = (e: TouchEvent) => {
      if (window.scrollY === 0) {
        startY.current = e.touches[0].clientY
      }
    }

    const onTouchMove = (e: TouchEvent) => {
      if (startY.current === 0) return
      distance.current = e.touches[0].clientY - startY.current
      if (distance.current > 0 && window.scrollY === 0) {
        e.preventDefault()
        const dampened = Math.min(distance.current * 0.4, 100)
        document.documentElement.style.setProperty('--pull-distance', `${dampened}px`)
      }
    }

    const onTouchEnd = async () => {
      if (distance.current > 60) {
        await onRefresh()
      }
      startY.current = 0
      distance.current = 0
      document.documentElement.style.setProperty('--pull-distance', '0px')
    }

    document.addEventListener('touchstart', onTouchStart, { passive: true })
    document.addEventListener('touchmove', onTouchMove, { passive: false })
    document.addEventListener('touchend', onTouchEnd)

    return () => {
      document.removeEventListener('touchstart', onTouchStart)
      document.removeEventListener('touchmove', onTouchMove)
      document.removeEventListener('touchend', onTouchEnd)
    }
  }, [onRefresh, disabled])
}
```

### Usage in BoardView

```tsx
// src/components/BoardView.tsx
import { usePullToRefresh } from '../hooks/usePullToRefresh'
import { useBoardData } from '../hooks/useBoardData'

export function BoardView() {
  const { data, refetch } = useBoardData()
  usePullToRefresh(refetch)

  return (
    <div className="board-view">
      <div className="pull-indicator" />
      {/* columns */}
    </div>
  )
}
```

### CSS

```css
/* src/styles/board.css */
.pull-indicator {
  height: var(--pull-distance, 0);
  transition: height 0.2s ease;
  display: flex;
  align-items: center;
  justify-content: center;
}
```

---

## 3. Theme Toggle

### Approach
A `ThemeProvider` context that reads the user's preference from `localStorage` (defaulting to system preference via `prefers-color-scheme`), toggles a `data-theme` attribute on `<html>`, and exposes `useTheme()`.

### Implementation

```tsx
// src/context/ThemeContext.tsx
import { createContext, useContext, useEffect, useState, ReactNode } from 'react'

type Theme = 'light' | 'dark'

interface ThemeContextValue {
  theme: Theme
  toggle: () => void
}

const ThemeContext = createContext<ThemeContextValue>({
  theme: 'light',
  toggle: () => {},
})

function getInitialTheme(): Theme {
  const stored = localStorage.getItem('kanban-theme')
  if (stored === 'light' || stored === 'dark') return stored
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'
}

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<Theme>(getInitialTheme)

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme)
    localStorage.setItem('kanban-theme', theme)
  }, [theme])

  const toggle = () => setTheme(t => (t === 'light' ? 'dark' : 'light'))

  return (
    <ThemeContext.Provider value={{ theme, toggle }}>
      {children}
    </ThemeContext.Provider>
  )
}

export const useTheme = () => useContext(ThemeContext)
```

### Toggle Component

```tsx
// src/components/ThemeToggle.tsx
import { useTheme } from '../context/ThemeContext'

export function ThemeToggle() {
  const { theme, toggle } = useTheme()
  return (
    <button onClick={toggle} aria-label={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}>
      {theme === 'light' ? '🌙' : '☀️'}
    </button>
  )
}
```

### CSS Variables

```css
/* src/styles/theme.css */
:root[data-theme='light'] {
  --bg: #ffffff;
  --text: #1a1a1a;
  --surface: #f5f5f5;
  --border: #e0e0e0;
}

:root[data-theme='dark'] {
  --bg: #121212;
  --text: #e8e8e8;
  --surface: #1e1e1e;
  --border: #333333;
}
```

---

## 4. Empty States

### Approach
A reusable `<EmptyState>` component with icon, title, description, and optional CTA. Used when a board has no columns, a column has no tickets, or a filter returns no results.

### Implementation

```tsx
// src/components/EmptyState.tsx
import { ReactNode } from 'react'

interface EmptyStateProps {
  icon: ReactNode
  title: string
  description: string
  action?: { label: string; onClick: () => void }
}

export function EmptyState({ icon, title, description, action }: EmptyStateProps) {
  return (
    <div className="empty-state" role="status">
      <div className="empty-state-icon">{icon}</div>
      <h3>{title}</h3>
      <p>{description}</p>
      {action && (
        <button onClick={action.onClick}>{action.label}</button>
      )}
    </div>
  )
}
```

### Usage Examples

```tsx
// src/components/BoardView.tsx
import { EmptyState } from './EmptyState'

export function BoardView() {
  const { columns } = useBoardData()

  if (columns.length === 0) {
    return (
      <EmptyState
        icon="📋"
        title="No columns yet"
        description="Create your first column to start organizing tickets."
        action={{ label: 'Add Column', onClick: openColumnDialog }}
      />
    )
  }
  return (/* board render */)
}
```

```tsx
// src/components/Column.tsx
export function Column({ column }: { column: Column }) {
  if (column.tickets.length === 0) {
    return (
      <EmptyState
        icon="🎫"
        title="No tickets"
        description="Drag a ticket here or create a new one."
      />
    )
  }
  return (/* ticket list */)
}
```

### CSS

```css
/* src/styles/empty-state.css */
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 3rem 1.5rem;
  text-align: center;
  color: var(--text-muted);
}
.empty-state-icon { font-size: 2.5rem; margin-bottom: 0.75rem; }
.empty-state h3 { margin: 0 0 0.5rem; font-size: 1.1rem; }
.empty-state p { margin: 0 0 1rem; font-size: 0.9rem; }
```

